-- Table: merchant_api_logs_mv (MaterializedView)
CREATE MATERIALIZED VIEW clickhouse_local.merchant_api_logs_mv TO clickhouse_local.merchant_api_logs
(
    `transaction_reference` String,
    `endpoint_url` String,
    `signature` String,
    `request_payload` String,
    `response_payload` String,
    `req_header` String,
    `resp_header` String,
    `http_status_code` String,
    `request_date` Date,
    `request_timestamp` DateTime64(6, \'Asia/Jakarta\'),
    `response_timestamp` DateTime64(6, \'Asia/Jakarta\'),
    `merchant_id` String,
    `merchant_name` String,
    `merchant_channel_id` String,
    `channel` String,
    `error_message` String
)
AS SELECT
    transaction_reference,
    endpoint_url,
    signature,
    request_payload,
    response_payload,
    req_header,
    resp_header,
    http_status_code,
    toDate(parseDateTimeBestEffort(request_date, 6, \'Asia/Jakarta\')) AS request_date,
    parseDateTimeBestEffort(request_timestamp, 6, \'Asia/Jakarta\') AS request_timestamp,
    parseDateTimeBestEffort(response_timestamp, 6, \'Asia/Jakarta\') AS response_timestamp,
    merchant_id,
    merchant_name,
    merchant_channel_id,
    channel,
    error_message
FROM clickhouse_local.kafka_merchant_api_logs
;

-- (data skipped for engine: MaterializedView)

-- Table: merchant_banks (ReplacingMergeTree)
CREATE TABLE clickhouse_local.merchant_banks
(
    `id` UUID,
    `merchant_id` UUID,
    `bank_info_id` UUID,
    `account_number` String DEFAULT \'\',
    `account_name` String DEFAULT \'\',
    `created_at` DateTime DEFAULT now(),
    `updated_at` DateTime DEFAULT now(),
    `created_by` String,
    `updated_by` String,
    `deleted_at` DateTime,
    `deleted_by` String,
    `is_default` Bool
)
ENGINE = ReplacingMergeTree(updated_at)
ORDER BY id
SETTINGS index_granularity = 8192
;

-- Table: merchant_channels (Log)
CREATE TABLE clickhouse_local.merchant_channels
(
    `id` String,
    `created_at` DateTime,
    `created_by` String,
    `updated_at` DateTime,
    `updated_by` String,
    `deleted_at` DateTime,
    `deleted_by` String,
    `merchant_id` String,
    `master_channel_id` String,
    `transaction_type` String,
    `merchant_callback_url` String,
    `retry_callback_count` Int64,
