-- Table: provider_channels (ReplacingMergeTree)
CREATE TABLE clickhouse_local.provider_channels
(
    `id` UUID,
    `provider_id` UUID,
    `master_channel_id` UUID,
    `transaction_type` String DEFAULT \'\',
    `created_at` DateTime DEFAULT now(),
    `updated_at` DateTime DEFAULT now()
)
ENGINE = ReplacingMergeTree(updated_at)
ORDER BY id
SETTINGS index_granularity = 8192
;

-- Table: providers (ReplacingMergeTree)
CREATE TABLE clickhouse_local.providers
(
    `id` UUID,
    `name` String,
    `created_at` DateTime DEFAULT now(),
    `updated_at` DateTime DEFAULT now(),
    `created_by` String,
    `updated_by` String,
    `deleted_at` DateTime,
    `deleted_by` String,
    `adapter_name` String,
    `status` String,
    `adapter_deployment_service` String,
    `api_timeout` Int64,
    `api_retry` Int64,
    `deposit_balance` Decimal(16, 2)
)
ENGINE = ReplacingMergeTree(updated_at)
ORDER BY id
SETTINGS index_granularity = 8192
;

-- Table: provisioning_logs (MergeTree)
CREATE TABLE clickhouse_local.provisioning_logs
(
    `provider_id` String,
    `adapter_name` String,
    `provider_name` String,
    `provisioning_datetime` DateTime64(3),
    `provisioning_date` Date,
    `provider_status` String,
    `error_message` String,
    `provider_channels` String
)
ENGINE = MergeTree
PARTITION BY toYYYYMMDD(provisioning_date)
ORDER BY provisioning_datetime
SETTINGS index_granularity = 8192
;

